export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  AU: 'Australia',
  BR: 'Brazil',
  CA: 'Canada',
  CN: 'China',
  DE: 'Germany',
  FR: 'France',
  GB: 'United Kingdom',
  IN: 'India',
  JP: 'Japan',
  US: 'United States',
}

export function geoFromHeaders(headers: Headers): Geo {
  const city =
    headers.get('x-vercel-ip-city') || undefined

  const vercelCountry =
    headers.get('x-vercel-ip-country') || undefined
  const cfCountry =
    headers.get('cf-ipcountry') || undefined
  const countryCode = (vercelCountry || cfCountry)?.toUpperCase()

  const country = countryCode ? COUNTRY_NAMES[countryCode] : undefined

  const region =
    headers.get('x-vercel-ip-country-region') || undefined
  const latitude =
    headers.get('x-vercel-ip-latitude') || undefined
  const longitude =
    headers.get('x-vercel-ip-longitude') || undefined
  const timezone =
    headers.get('x-vercel-ip-timezone') || undefined

  return { city, country, countryCode, region, latitude, longitude, timezone }
}

export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) return false
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth's radius in km
  const toRad = (deg: number) => (deg * Math.PI) / 180

  const φ1 = toRad(parseFloat(lat1))
  const φ2 = toRad(parseFloat(lat2))
  const Δφ = toRad(parseFloat(lat2) - parseFloat(lat1))
  const Δλ = toRad(parseFloat(lon2) - parseFloat(lon1))

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2)

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

  return R * c
}

